SELECT ?westernEndLabel ?easternEndLabel WHERE {
  wd:Q34640 wdt:P403 ?westernEnd .
  ?easternEnd wdt:P361 wd:Q34640 ;
             wdt:P31/wdt:P279* wd:Q226722 .
  ?westernEnd rdfs:label ?westernEndLabel .
  ?easternEnd rdfs:label ?easternEndLabel .
  FILTER (lang(?westernEndLabel) = "en")
  FILTER (lang(?easternEndLabel) = "en")
}

